import psycopg2

def search_users(username=None, email=None, role=None, status=None):
    # Establish a connection to the database
    conn = psycopg2.connect(
        dbname='your_db_name',
        user='your_username',
        password='your_password',
        host='your_host',
        port='your_port'
    )
    cursor = conn.cursor()

    # Build the base query
    query = "SELECT * FROM users WHERE TRUE"
    filters = []

    # Append filters based on provided parameters
    if username:
        query += " AND username = %s"
        filters.append(username)
    if email:
        query += " AND email = %s"
        filters.append(email)
    if role:
        query += " AND role = %s"
        filters.append(role)
    if status:
        query += " AND status = %s"
        filters.append(status)

    # Execute the query with filters
    cursor.execute(query, filters)
    results = cursor.fetchall()

    # Clean up
    cursor.close()
    conn.close()

    return results